/**
 * Tests for telemetry HTTP sink.
 *
 * Validates:
 *   - URL resolution chain (ORK_HQ_TELEMETRY_URL → HQ_API_URL → null)
 *   - Token resolution chain (env → plugin config → cache → null)
 *   - file→event mapping (every known JSONL file → matching CCHookEvent value)
 *   - Unknown files no-op
 *   - postAnalyticsToSink is fire-and-forget (no thrown errors, returns sync)
 *   - postAnalyticsToSink no-ops when url/token/event are missing
 *
 * NOT covered here (would require integration env):
 *   - Real HTTP behavior
 *   - Circuit breaker file persistence across process restarts
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';

vi.mock('../../lib/paths.js', () => ({
  getHomeDir: vi.fn(() => '/mock/home'),
  joinPath: (...args: string[]) => args.join('/'),
}));

vi.mock('node:fs', async () => {
  const actual = await vi.importActual<typeof import('node:fs')>('node:fs');
  return {
    ...actual,
    existsSync: vi.fn(() => false),
    readFileSync: vi.fn(),
    writeFileSync: vi.fn(),
    mkdirSync: vi.fn(),
  };
});

import {
  resolveSinkUrl,
  resolveSinkToken,
  fileToEventName,
  postAnalyticsToSink,
} from '../../lib/telemetry-http-sink.js';

describe('telemetry-http-sink', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    vi.clearAllMocks();
    process.env = { ...originalEnv };
    delete process.env.ORK_HQ_TELEMETRY_URL;
    delete process.env.ORK_HQ_TELEMETRY_USE_HQ_API;
    delete process.env.HQ_API_URL;
    delete process.env.CC_HOOKS_SECRET_TOKEN;
    delete process.env.CLAUDE_PLUGIN_CONFIG;
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  // ─── resolveSinkUrl ──────────────────────────────────────────────────────

  describe('resolveSinkUrl', () => {
    it('returns null when no env vars are set', () => {
      expect(resolveSinkUrl()).toBeNull();
    });

    it('prefers ORK_HQ_TELEMETRY_URL when set', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq';
      expect(resolveSinkUrl()).toBe('https://my.hq');
    });

    it('strips trailing slash from ORK_HQ_TELEMETRY_URL', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq/';
      expect(resolveSinkUrl()).toBe('https://my.hq');
    });

    it('falls back to HQ_API_URL when ORK_HQ_TELEMETRY_USE_HQ_API=1', () => {
      process.env.HQ_API_URL = 'https://shared.hq';
      process.env.ORK_HQ_TELEMETRY_USE_HQ_API = '1';
      expect(resolveSinkUrl()).toBe('https://shared.hq');
    });

    it('ignores HQ_API_URL when opt-in flag is missing', () => {
      process.env.HQ_API_URL = 'https://shared.hq';
      expect(resolveSinkUrl()).toBeNull();
    });

    it('ignores HQ_API_URL when opt-in flag is "0"', () => {
      process.env.HQ_API_URL = 'https://shared.hq';
      process.env.ORK_HQ_TELEMETRY_USE_HQ_API = '0';
      expect(resolveSinkUrl()).toBeNull();
    });
  });

  // ─── resolveSinkToken ────────────────────────────────────────────────────

  describe('resolveSinkToken', () => {
    it('returns null when no source has a token', () => {
      expect(resolveSinkToken()).toBeNull();
    });

    it('returns CC_HOOKS_SECRET_TOKEN when set in env', () => {
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok-env';
      expect(resolveSinkToken()).toBe('tok-env');
    });

    it('reads token from CLAUDE_PLUGIN_CONFIG when env var missing', () => {
      process.env.CLAUDE_PLUGIN_CONFIG = JSON.stringify({ CC_HOOKS_SECRET_TOKEN: 'tok-cfg' });
      expect(resolveSinkToken()).toBe('tok-cfg');
    });

    it('env var beats plugin config', () => {
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok-env';
      process.env.CLAUDE_PLUGIN_CONFIG = JSON.stringify({ CC_HOOKS_SECRET_TOKEN: 'tok-cfg' });
      expect(resolveSinkToken()).toBe('tok-env');
    });

    it('handles malformed CLAUDE_PLUGIN_CONFIG gracefully', () => {
      process.env.CLAUDE_PLUGIN_CONFIG = '{not json';
      expect(resolveSinkToken()).toBeNull();
    });
  });

  // ─── fileToEventName ─────────────────────────────────────────────────────

  describe('fileToEventName', () => {
    it.each([
      ['skill-usage.jsonl', 'OrkSkillUsage'],
      ['agent-usage.jsonl', 'OrkAgentUsage'],
      ['hook-timing.jsonl', 'OrkHookTiming'],
      ['cache-breaks.jsonl', 'OrkCacheBreaks'],
      ['secret-audit.jsonl', 'OrkSecretAudit'],
      ['dx-signals.jsonl', 'OrkDxSignals'],
      ['session-summary.jsonl', 'OrkSessionSummary'],
      ['session-start-perf.jsonl', 'OrkSessionStartPerf'],
      ['team-activity.jsonl', 'OrkTeamActivity'],
      ['subagent-quality.jsonl', 'OrkSubagentQuality'],
      ['task-usage.jsonl', 'OrkTaskUsage'],
    ])('maps %s → %s', (file, expected) => {
      expect(fileToEventName(file)).toBe(expected);
    });

    it('returns null for unknown filenames (avoids Generic-row pollution)', () => {
      expect(fileToEventName('unknown.jsonl')).toBeNull();
      expect(fileToEventName('skill-usage.json')).toBeNull(); // wrong ext
      expect(fileToEventName('')).toBeNull();
    });
  });

  // ─── postAnalyticsToSink ─────────────────────────────────────────────────

  describe('postAnalyticsToSink', () => {
    let fetchSpy: ReturnType<typeof vi.spyOn>;

    beforeEach(() => {
      fetchSpy = vi.spyOn(globalThis, 'fetch').mockResolvedValue(
        new Response(null, { status: 200 }),
      );
    });

    afterEach(() => {
      fetchSpy.mockRestore();
    });

    it('no-ops silently when no URL is configured', () => {
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok';
      postAnalyticsToSink('skill-usage.jsonl', { skill: 'demo' });
      expect(fetchSpy).not.toHaveBeenCalled();
    });

    it('no-ops silently when no token is available', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq';
      postAnalyticsToSink('skill-usage.jsonl', { skill: 'demo' });
      expect(fetchSpy).not.toHaveBeenCalled();
    });

    it('no-ops silently when filename is unknown', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq';
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok';
      postAnalyticsToSink('mystery.jsonl', { foo: 'bar' });
      expect(fetchSpy).not.toHaveBeenCalled();
    });

    it('returns synchronously even when fetch hangs', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq';
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok';
      // Make fetch hang forever — postAnalyticsToSink must still return.
      fetchSpy.mockReturnValue(new Promise(() => {}));
      const start = Date.now();
      const result = postAnalyticsToSink('skill-usage.jsonl', { skill: 'demo' });
      expect(result).toBeUndefined();
      // Generous threshold: vitest cold-start can add ~150ms. The real
      // invariant is "doesn't await the hung fetch" (multi-second).
      expect(Date.now() - start).toBeLessThan(1000);
    });

    it('never throws even when fetch rejects', () => {
      process.env.ORK_HQ_TELEMETRY_URL = 'https://my.hq';
      process.env.CC_HOOKS_SECRET_TOKEN = 'tok';
      fetchSpy.mockRejectedValue(new Error('boom'));
      expect(() =>
        postAnalyticsToSink('skill-usage.jsonl', { skill: 'demo' }),
      ).not.toThrow();
    });
  });
});
